def get_sample_dataframe(name: str) -> pd.DataFrame:
    """Return a pandas DataFrame for the named sample dataset."""
    ds = SAMPLE_DATASETS[name]
    return pd.DataFrame(ds["data"])


def list_sample_datasets() -> list[str]:
    return list(SAMPLE_DATASETS.keys())


def get_sample_info(name: str) -> dict:
    ds = SAMPLE_DATASETS[name]
    return {k: v for k, v in ds.items() if k != "data"}
